        if (name && name.textContent.includes(label)) {
          var dot = item.querySelector('.conn-dot');
          if (dot) {
            dot.classList.remove('pending');
            dot.classList.add('fail');
          }
        }
      });
    });
  }
}

function setCount(id, n, cls) {
  var el = document.getElementById(id);
  el.textContent = n;
  el.className = 'count-num' + (cls ? ' ' + cls : '');
}

function startResearch() {
  var topic = document.getElementById('topic').value.trim();
  if (!topic) { alert('请输入题目'); return; }
  var caseId = currentCaseId || genCaseId();
  currentCaseId = caseId;
  document.getElementById('startBtn').disabled = true;
  document.getElementById('statusBar').textContent = '提交中...';
  document.getElementById('papersPanel').style.display = 'none';
  document.getElementById('evidenceSection').style.display = 'none';
  document.getElementById('wpSection').style.display = 'none';
  document.getElementById('finalSection').style.display = 'none';
  document.getElementById('paperList').innerHTML = '';
  allPapers = [];
  setCount('cnt-papers', 0); setCount('cnt-repos', 0); setCount('cnt-datasets', 0);
  setCount('cnt-surveys', 0); setCount('cnt-expanded', 0); setCount('cnt-seeds', 0);
  initStateMachine();
  loadConnectivity();

  fetch('/api/v1/research/', {
    method: 'POST', headers: {'Content-Type': 'application/json'},
    body: JSON.stringify({case_id: caseId, topic: topic})
  }).then(function(r) { return r.json(); }).then(function() {
    connectSSE(caseId);
  });
}

function connectSSE(caseId) {
  var es = new EventSource('/api/v1/research/' + caseId + '/stream');

  es.addEventListener('search_started', function() {
    document.getElementById('statusBar').textContent = '搜索中...';
    markNodeCurrent('retrieve');
  });

  es.addEventListener('adapter_result', function(e) {
    var d = JSON.parse(e.data);
    // Already handled by adapter_status
  });

  es.addEventListener('adapter_status', function(e) {
    var d = JSON.parse(e.data);
    if (d.per_adapter) {
      updateConnFromAdapter(d.per_adapter, d.failed_adapters);
    }
  });

  es.addEventListener('search_completed', function(e) {
    advanceProgress('retrieve');
    markNodeCurrent('filter');
  });

  es.addEventListener('filter_result', function(e) {
    advanceProgress('filter');
    markNodeCurrent('verify');
  });

  es.addEventListener('verify_completed', function(e) {
    var d = JSON.parse(e.data);
    advanceProgress('verify');
    if (d.round === 1) {
      markNodeCurrent('gate');
    } else {
      advanceProgress('verify2');
      markNodeCurrent('gate2');
    }
  });

  es.addEventListener('candidate_count', function(e) {
    var d = JSON.parse(e.data);
    if (d.papers !== undefined) {
      setCount('cnt-papers', d.papers);
      if (d.accept !== undefined) setCount('cnt-papers', d.papers, d.accept > 0 ? 'pos' : 'neg');
    }
  });

  es.addEventListener('expansion_started', function(e) {
    var d = JSON.parse(e.data);
    if (d.n_seeds !== undefined) setCount('cnt-seeds', d.n_seeds);
    advanceProgress('gate');
    markNodeCurrent('expand');
  });

  es.addEventListener('expansion_completed', function(e) {
    var d = JSON.parse(e.data);
    if (d.total_expanded !== undefined) setCount('cnt-expanded', d.total_expanded);
    if (d.n_surveys !== undefined) setCount('cnt-surveys', d.n_surveys);
    if (d.n_repos !== undefined) setCount('cnt-repos', d.n_repos);
    advanceProgress('expand');
  });

  es.addEventListener('node_complete', function(e) {
    var d = JSON.parse(e.data);
    advanceProgress(d.node);
    var nextMap = {
      'dataset_repo_extractor': 'graph', 'evidence_graph_builder': 'classify',
      'baseline_classifier': 'feas', 'feasibility_assessor': 'workpkg',
      'work_package': 'innov', 'innovation_extractor': 'sota',
      'sota_matcher': 'narrative', 'narrative_builder': 'review',
      'low_bar_review': 'optimize', 'optimization_advisor': 'devils',
      'devils_advocate': 'human', 'human_gate': 'final'
    };
    if (nextMap[d.node]) markNodeCurrent(nextMap[d.node]);
  });

  es.addEventListener('done', function(e) {
    var d = JSON.parse(e.data);
    document.getElementById('statusBar').textContent = '完成! 耗时 ' + d.total_elapsed_s + 's';
    setProgress(TOTAL_NODES);
    markNodeDone('final');
    es.close();
    document.getElementById('startBtn').disabled = false;
    fetchAndRenderAll(caseId);
  });

  es.addEventListener('error', function(e) {
    try { var d = JSON.parse(e.data); document.getElementById('statusBar').textContent = '错误: ' + d.message; } catch(err) {}
  });

  setTimeout(function() {
    if (es.readyState === 2) {
      var poll = setInterval(function() {
        fetch('/api/v1/research/' + caseId + '/status').then(function(r) { return r.json(); }).then(function(s) {
          if (s.status === 'done') { clearInterval(poll); fetchAndRenderAll(caseId); document.getElementById('startBtn').disabled = false; }
          if (s.status === 'error') { clearInterval(poll); document.getElementById('startBtn').disabled = false; }
        });
      }, 2000);
    }
  }, 3000);
}

function fetchAndRenderAll(caseId) {
  fetch('/api/v1/research/' + caseId + '/state').then(function(r) { return r.json(); }).then(function(st) {
    allPapers = [];
    var vp = st.verified_papers || [];
    var wp = st.weak_papers || [];
    for (var i = 0; i < vp.length; i++) allPapers.push(vp[i]);
    for (var i = 0; i < wp.length; i++) allPapers.push(wp[i]);
    renderPapers();
    renderEvidenceGraph(st);
    renderWorkPackages(st.work_packages || []);
    renderFinal(st.final_recommendation || {}, st);
    // Update counts from final state
    setCount('cnt-papers', (st.verified_papers || []).length + (st.weak_papers || []).length);
    setCount('cnt-repos', (st.repo_candidates || []).length);
    setCount('cnt-datasets', (st.dataset_candidates || []).length);
    setCount('cnt-surveys', (st.surveys_found || []).length);
    setCount('cnt-expanded', (st.expanded_papers || []).length);
    setCount('cnt-seeds', (st.seed_papers || []).length);
  }).catch(function() {});
}

function renderPapers() {
  document.getElementById('papersPanel').style.display = '';
  var html = '';
  for (var i = 0; i < allPapers.length; i++) {
    var p = allPapers[i];
    var verdict = p.verdict || 'unknown';
    var cls = verdict === 'accept' ? 'accept' : (verdict === 'weak_reject' ? 'weak' : 'reject');
    var icon = verdict === 'accept' ? '✓' : (verdict === 'weak_reject' ? '⚠' : '✗');
    var title = (p.title || '').substring(0, 80);
    var rel = p.relation_to_topic || '';
    var uploadTag = p.source === 'user_upload' ? ' <span style="color:#059669;font-size:10px;">[用户上传]</span>' : '';
    html += '<div class="paper-card ' + cls + '">';
    html += '<span class="verdict-icon">' + icon + '</span>';
    html += '<div class="paper-body">';
    html += '<div class="paper-title">' + title + uploadTag + '</div>';
    if (rel) html += '<div class="paper-rel">' + rel + '</div>';
    html += '</div></div>';
  }
  document.getElementById('paperList').innerHTML = html || '<div style="color:#94a3b8;font-size:13px;padding:8px;">无论文</div>';
}

function renderEvidenceGraph(st) {
  document.getElementById('evidenceSection').style.display = '';
  var groups = [
    {label: 'Baseline', items: st.baseline_candidates || []},
    {label: 'Parallel', items: st.parallel_candidates || []},
    {label: 'Survey', items: (st.surveys || []).concat(st.surveys_found || [])},
    {label: 'Dataset', items: st.dataset_candidates || []},
    {label: 'Repo', items: (st.repo_candidates || []).concat(st.repos_found || [])}
  ];
  var html = '';
  for (var g = 0; g < groups.length; g++) {
    var items = groups[g].items;
    html += '<div class="eg-group"><div class="eg-group-title">' + groups[g].label + ' (' + items.length + ')</div>';
    for (var i = 0; i < Math.min(items.length, 10); i++) {
      var title = items[i].title || items[i].name || items[i].url || '';
      html += '<div class="eg-item">' + (title.substring(0, 80) || '') + '</div>';
    }
    if (items.length > 10) html += '<div class="eg-item">... 还有 ' + (items.length - 10) + ' 条</div>';
    html += '</div>';
  }
  document.getElementById('evidenceGraph').innerHTML = html;
}

function renderWorkPackages(wps) {
  document.getElementById('wpSection').style.display = '';
  var html = '';
  for (var i = 0; i < wps.length; i++) {
    var wp = wps[i];
    var title = wp.title || wp.approach || wp.name || ('工作包 ' + (i + 1));
    var desc = wp.description || wp.summary || '';
    html += '<div class="wp-item"><b>' + (i + 1) + '. ' + title + '</b>';
    if (desc) html += '<br><span style="color:#64748b">' + desc.substring(0, 200) + '</span>';
    html += '</div>';
  }
  document.getElementById('workPackages').innerHTML = html || '<div style="color:#94a3b8;font-size:13px">无工作包</div>';
}

function renderFinal(final, st) {
  document.getElementById('finalSection').style.display = '';
  var html = '';
  if (final.low_bar_status) {
    var sCls = final.low_bar_status === 'pass' ? 'green' : (final.low_bar_status === 'blocked' ? 'red' : 'orange');
    html += '<span class="final-badge ' + sCls + '">' + final.low_bar_status + '</span>';
  }
  if (st.feasibility_report && st.feasibility_report.verdict) {
    var fCls = st.feasibility_report.verdict === 'feasible' ? 'green' : (st.feasibility_report.verdict === 'risky' ? 'orange' : 'red');
    html += '<span class="final-badge ' + fCls + '">可行性: ' + st.feasibility_report.verdict + ' (' + st.feasibility_report.score + '分)</span>';
  }
  if (st.review_report && st.review_report.overall_verdict) {
    var rCls = st.review_report.overall_verdict === 'ACCEPT' ? 'green' : (st.review_report.overall_verdict === 'MINOR_REVISION' ? 'orange' : 'red');
    html += '<span class="final-badge ' + rCls + '">审查: ' + st.review_report.overall_verdict + '</span>';
  }
  if (final.summary) html += '<div style="margin-top:6px">' + final.summary + '</div>';
  if (!html) html = '<div style="color:#94a3b8">无最终推荐</div>';
  document.getElementById('finalReport').innerHTML = html;
}

function viewCase(caseId) {
  if (!caseId) return;
  initStateMachine();
  setProgress(TOTAL_NODES);
  // Mark all nodes as done
  document.querySelectorAll('.state-node').forEach(function(n) { n.classList.add('done'); });
  fetchAndRenderAll(caseId);
  document.getElementById('statusBar').textContent = '查看历史: ' + caseId;
}

var uploadedPapers = [];
var currentCaseId = null;

function uploadPaper() {
  var title = document.getElementById('uploadTitle').value.trim();
  var doi = document.getElementById('uploadDoi').value.trim();
  var arxiv = document.getElementById('uploadArxiv').value.trim();
  var role = document.getElementById('uploadRole').value;
  if (!title && !doi && !arxiv) { alert('请至少输入标题、DOI 或 arXiv ID'); return; }
  if (!currentCaseId) { currentCaseId = genCaseId(); }
  document.getElementById('uploadTitle').value = '';
  document.getElementById('uploadDoi').value = '';
  document.getElementById('uploadArxiv').value = '';
  fetch('/api/v1/research/' + currentCaseId + '/papers', {
    method: 'POST', headers: {'Content-Type': 'application/json'},
    body: JSON.stringify({title: title, doi: doi, arxiv_id: arxiv, role: role})
  }).then(function(r) { return r.json(); }).then(function(d) {
    if (d.paper) {
      uploadedPapers.push(d.paper);
      renderUploadList();
    }
  }).catch(function(e) { alert('上传失败: ' + e); });
}

function renderUploadList() {
  var html = '';
  for (var i = 0; i < uploadedPapers.length; i++) {
    var p = uploadedPapers[i];
    var tag = p.arxiv_id ? 'arXiv:' + p.arxiv_id : (p.doi ? 'DOI:' + p.doi : 'title');
    html += '<div style="font-size:12px;padding:3px 0;color:#059669;">✓ ' + (p.title || tag) + ' <span style="color:#94a3b8">[' + (p.role || 'baseline') + ']</span></div>';
  }
  document.getElementById('uploadList').innerHTML = html || '<div style="font-size:12px;color:#cbd5e1;">暂无上传论文</div>';
}

// Init
initStateMachine();
loadHistory();
renderUploadList();
</script>
</body>
</html>

